async (page) => {
  const weaponInfo = await page.evaluate(() => {
    const p = window.game.player;
    if (!p) return 'no player';
    return JSON.stringify({
      weaponKey: p.getWeaponType ? p.getWeaponType() : 'unknown',
      equipment: p.equipment ? {
        weapon: p.equipment.getWeapon ? p.equipment.getWeapon() : 'unknown',
        slots: p.equipment.slots ? Object.keys(p.equipment.slots) : 'unknown'
      } : 'no equipment obj',
      attackStyle: p.attackStyle
    });
  });
  return weaponInfo;
}

async (page) => {
  // Talk to Forester multiple times to trigger quest hand-in
  for (let i = 0; i < 6; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), '1-51215128');
    await page.waitForTimeout(1200);
  }
  // Click quest button
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const logs = s.inventory ? s.inventory.filter(x => x.key === 'logs').reduce((sum, x) => sum + x.count, 0) : 0;
    return JSON.stringify({
      pos: s.player_position,
      hp: s.player_stats.hp,
      logs: logs,
      quests: s.quests.filter(q => q.started)
    });
  });
  return state;
}

