async (page) => {
  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 400);
  });
  await page.waitForTimeout(3000);

  // Re-set attack style
  await page.evaluate(() => window.game.player.setAttackStyle(0));

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const weapon = window.game.player.equipments?.[4]?.key || 'empty';
    return JSON.stringify({ pos: s.player_position, hp: s.player_stats.hp, weapon, logs: s.inventory?.filter(x=>x.key==='logs').reduce((sum,x)=>sum+x.count,0) });
  });
  return state;
}

